"use client";

import { useState, useEffect } from "react";
import {
    Users,
    Search,
    CheckCircle2,
    XCircle,
    Shield,
    Clock,
    Ban,
    Loader2,
    UserCheck,
} from "lucide-react";

interface UserData {
    id: string;
    name: string;
    email: string;
    role: "SUPER_ADMIN" | "ADMIN" | "USER";
    status: "PENDING" | "APPROVED" | "SUSPENDED";
    createdAt: string;
    _count: { baniUsers: number };
}

const statusConfig: Record<string, { label: string; color: string; icon: any }> = {
    PENDING: { label: "Menunggu", color: "bg-gold-50 text-gold-700 border-gold-200", icon: Clock },
    APPROVED: { label: "Aktif", color: "bg-green-50 text-green-700 border-green-200", icon: CheckCircle2 },
    SUSPENDED: { label: "Ditangguhkan", color: "bg-red-50 text-red-700 border-red-200", icon: Ban },
};

const roleLabels: Record<string, string> = {
    SUPER_ADMIN: "Super Admin",
    ADMIN: "Admin",
    USER: "Pengguna",
};

export default function AdminUsersPage() {
    const [users, setUsers] = useState<UserData[]>([]);
    const [search, setSearch] = useState("");
    const [filterStatus, setFilterStatus] = useState("");
    const [loading, setLoading] = useState(true);
    const [actionLoading, setActionLoading] = useState<string | null>(null);

    useEffect(() => {
        fetchUsers();
    }, []);

    const fetchUsers = async () => {
        try {
            const res = await fetch("/api/admin/users");
            const data = await res.json();
            setUsers(data);
        } catch (err) {
            console.error("Failed to fetch users:", err);
        } finally {
            setLoading(false);
        }
    };

    const updateUser = async (userId: string, data: { status?: string; userRole?: string }) => {
        setActionLoading(userId);
        try {
            const res = await fetch("/api/admin/users", {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ userId, ...data }),
            });

            if (res.ok) {
                await fetchUsers();
            }
        } catch (err) {
            console.error("Failed to update user:", err);
        } finally {
            setActionLoading(null);
        }
    };

    const filtered = users.filter((u) => {
        const matchSearch =
            u.name.toLowerCase().includes(search.toLowerCase()) ||
            u.email.toLowerCase().includes(search.toLowerCase());
        const matchStatus = !filterStatus || u.status === filterStatus;
        return matchSearch && matchStatus;
    });

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[50vh]">
                <Loader2 className="w-8 h-8 animate-spin text-primary-500" />
            </div>
        );
    }

    return (
        <div className="max-w-6xl mx-auto space-y-6">
            <div>
                <h1 className="text-2xl sm:text-3xl font-bold text-surface-900">
                    Kelola Pengguna
                </h1>
                <p className="text-surface-500 mt-1">
                    Approve, suspend, dan atur role pengguna
                </p>
            </div>

            {/* Filters */}
            <div className="flex flex-col sm:flex-row gap-3">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-surface-400" />
                    <input
                        type="text"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        className="touch-target w-full pl-10 pr-4 py-3 rounded-xl border border-surface-200 text-surface-900 placeholder-surface-400 focus:outline-none focus:border-primary-500 focus:ring-2 focus:ring-primary-500/20"
                        placeholder="Cari nama atau email..."
                    />
                </div>
                <div className="flex gap-2">
                    {["", "PENDING", "APPROVED", "SUSPENDED"].map((status) => (
                        <button
                            key={status}
                            onClick={() => setFilterStatus(status)}
                            className={`touch-target px-4 py-2.5 rounded-xl text-sm font-medium transition-all ${filterStatus === status
                                    ? "bg-primary-600 text-white shadow-md"
                                    : "bg-white border border-surface-200 text-surface-600 hover:bg-surface-50"
                                }`}
                        >
                            {status === "" ? "Semua" : statusConfig[status]?.label}
                        </button>
                    ))}
                </div>
            </div>

            {/* Users List */}
            <div className="rounded-2xl bg-white border border-surface-200 overflow-hidden">
                <div className="divide-y divide-surface-100">
                    {filtered.length === 0 ? (
                        <div className="p-8 text-center">
                            <Users className="w-10 h-10 text-surface-300 mx-auto mb-3" />
                            <p className="text-surface-500">Tidak ada pengguna ditemukan</p>
                        </div>
                    ) : (
                        filtered.map((user) => {
                            const status = statusConfig[user.status];
                            const StatusIcon = status.icon;
                            const isLoading = actionLoading === user.id;

                            return (
                                <div
                                    key={user.id}
                                    className="p-4 sm:p-5 flex flex-col sm:flex-row sm:items-center gap-4"
                                >
                                    {/* User Info */}
                                    <div className="flex items-center gap-3 flex-1">
                                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary-400 to-primary-600 flex items-center justify-center text-white text-sm font-semibold flex-shrink-0">
                                            {user.name[0].toUpperCase()}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 flex-wrap">
                                                <p className="text-sm font-semibold text-surface-900">
                                                    {user.name}
                                                </p>
                                                <span
                                                    className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-lg text-xs font-medium border ${status.color}`}
                                                >
                                                    <StatusIcon className="w-3 h-3" />
                                                    {status.label}
                                                </span>
                                                <span className="text-xs px-2 py-0.5 rounded-lg bg-surface-100 text-surface-500">
                                                    {roleLabels[user.role]}
                                                </span>
                                            </div>
                                            <p className="text-xs text-surface-400 mt-0.5">
                                                {user.email} · {user._count.baniUsers} bani
                                            </p>
                                        </div>
                                    </div>

                                    {/* Actions */}
                                    <div className="flex gap-2 ml-auto">
                                        {isLoading ? (
                                            <Loader2 className="w-5 h-5 animate-spin text-surface-400" />
                                        ) : (
                                            <>
                                                {user.status === "PENDING" && (
                                                    <button
                                                        onClick={() => updateUser(user.id, { status: "APPROVED" })}
                                                        className="touch-target inline-flex items-center gap-1.5 px-3 py-2 rounded-lg bg-green-50 text-green-700 text-sm font-medium hover:bg-green-100 transition-colors border border-green-200"
                                                    >
                                                        <UserCheck className="w-4 h-4" />
                                                        Approve
                                                    </button>
                                                )}
                                                {user.status === "APPROVED" && user.role !== "SUPER_ADMIN" && (
                                                    <button
                                                        onClick={() => updateUser(user.id, { status: "SUSPENDED" })}
                                                        className="touch-target inline-flex items-center gap-1.5 px-3 py-2 rounded-lg bg-red-50 text-red-700 text-sm font-medium hover:bg-red-100 transition-colors border border-red-200"
                                                    >
                                                        <Ban className="w-4 h-4" />
                                                        Suspend
                                                    </button>
                                                )}
                                                {user.status === "SUSPENDED" && (
                                                    <button
                                                        onClick={() => updateUser(user.id, { status: "APPROVED" })}
                                                        className="touch-target inline-flex items-center gap-1.5 px-3 py-2 rounded-lg bg-green-50 text-green-700 text-sm font-medium hover:bg-green-100 transition-colors border border-green-200"
                                                    >
                                                        <CheckCircle2 className="w-4 h-4" />
                                                        Aktifkan
                                                    </button>
                                                )}
                                            </>
                                        )}
                                    </div>
                                </div>
                            );
                        })
                    )}
                </div>
            </div>
        </div>
    );
}
